import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionFixed {

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        System.out.print("Enter a command to execute: ");
        String command = reader.readLine();

        // Fixed code: Use ProcessBuilder to set the command and arguments separately
        ProcessBuilder processBuilder = new ProcessBuilder();
        processBuilder.command("ls", command);

        Process process = processBuilder.start();

        BufferedReader inputStream = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;
        while ((line = inputStream.readLine()) != null) {
            System.out.println(line);
        }
    }
}

### Explanation:
취약유형: Command Injection
